mapper.select:
SELECT u.id, u.username, u.real_name, u.phone, u.email, u.avatar, u.status, u.tenant_type, u.tenant_id, u.org_id, u.last_login_time, u.create_time, o.org_name FROM sys_user u LEFT JOIN sys_org o ON o.id = u.org_id AND o.deleted = 0
u.deleted = 0
AND (u.username LIKE CONCAT('%', #{query.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR u.phone LIKE CONCAT('%', #{query.keyword}, '%'))
AND u.status = #{query.status}
AND u.tenant_type = #{query.tenantType}
AND u.org_id = #{query.orgId}
AND EXISTS (SELECT 1 FROM sys_user_role ur2 WHERE ur2.user_id = u.id AND ur2.role_id = #{query.roleId} AND ur2.deleted = 0)
ORDER BY u.create_time DESC
